import React from 'react';
import { Clock } from 'lucide-react';

const formatDuration = (ms) => {
  const minutes = Math.floor(ms / 60000);
  const seconds = ((ms % 60000) / 1000).toFixed(0);
  return `${minutes}:${Number(seconds) < 10 ? '0' : ''}${seconds}`;
};

const formatTimeAgo = (isoString) => {
  if (!isoString) return '';
  const date = new Date(isoString);
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

const RecentTracks = ({ tracks }) => {
  return (
    <div className="w-full">
      <div className="flex items-center justify-between mb-6 px-2">
        <h3 className="text-lg font-bold text-white tracking-tight">Recent History</h3>
        <button className="text-xs text-zinc-500 hover:text-white transition-colors uppercase tracking-wider font-semibold">
          View All
        </button>
      </div>

      <div className="flex flex-col">
        {/* Header */}
        <div className="grid grid-cols-[auto_1fr_1fr_auto] gap-4 px-4 py-2 border-b border-zinc-800 text-xs text-zinc-500 font-medium uppercase tracking-wider">
          <div className="w-8">#</div>
          <div>Title</div>
          <div className="hidden md:block">Album</div>
          <div className="flex items-center justify-end">
            <Clock className="h-4 w-4" />
          </div>
        </div>

        {/* Rows */}
        {tracks.map((track, index) => (
          <div 
            key={track.id} 
            className="group grid grid-cols-[auto_1fr_1fr_auto] gap-4 px-4 py-3 rounded-md hover:bg-zinc-800/40 transition-colors items-center cursor-default"
          >
            <div className="w-8 text-sm text-zinc-600 group-hover:text-white font-mono">
              {index + 1}
            </div>

            <div className="flex items-center gap-4 min-w-0">
              <img 
                src={track.albumArt} 
                alt={track.album} 
                className="h-10 w-10 rounded shadow-sm object-cover"
              />
              <div className="flex flex-col min-w-0">
                <span className="text-sm font-medium text-zinc-200 truncate group-hover:text-white">
                  {track.name}
                </span>
                <span className="text-xs text-zinc-500 truncate group-hover:text-zinc-400">
                  {track.artist.name}
                </span>
              </div>
            </div>

            <div className="hidden md:flex items-center min-w-0">
              <span className="text-sm text-zinc-500 truncate group-hover:text-zinc-300">
                {track.album}
              </span>
            </div>

            <div className="flex flex-col items-end gap-1">
               <span className="text-sm text-zinc-400 font-mono">
                {formatDuration(track.durationMs)}
              </span>
              <span className="text-[10px] text-zinc-600 group-hover:text-zinc-500">
                {formatTimeAgo(track.playedAt)}
              </span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default RecentTracks;

